  ('optician-moex-02693', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '若眼鏡度數為-1.00DS/-1.00DC×180，K = 43.00 D@180°/45.00 D@90°，頂點距離 = 12 mm，殘餘散光應為：', '["無殘餘散光", "有殘餘散光+1.00DC×180", "有殘餘散光+2.00DC×180", "有殘餘散光+1.00DC×090"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "21dccecf40fb", "answer_pdf_sha1": "332b43e00546", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02694', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '驗配硬式透氣隱形眼鏡時，試戴片的參數為：基弧 7.70 mm／直徑 9.5 mm／度數-3.00 DS。戴鏡驗光 （over-refraction）+6.0 DS視力1.0，其屈光度數應為多少？', '["+3.0 DS", "+3.5 DS", "+4.0 DS", "+4.5 DS"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "21dccecf40fb", "answer_pdf_sha1": "332b43e00546", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02695', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '若試片屈光度為-3.00 DS，戴鏡驗光屈光度為-7.00 DS，配戴者視力可達1.0，頂點距離 = 12 mm，隱形眼 鏡屈光度應為：（眼鏡屈光度-8.00 DS／頂點距離12 mm = -7.30 DS／頂點距離13 mm = -7.25 DS）（眼 鏡屈光度-7.00 DS／頂點距離12 mm = -6.46 DS／頂點距離13 mm = -6.42 DS）', '["-9.75 DS", "-10.00 DS", "-8.00 DS", "-9.25 DS"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:38+00:00", "source_pdf_sha1": "21dccecf40fb", "answer_pdf_sha1": "332b43e00546", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
